from flask import Flask, request, jsonify
import os
import json
import logging
from transformers import AutoTokenizer
import re

# Set up logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = Flask(__name__)

# Global variables
tokenizer = None
MODEL_NAME = "distilbert-base-uncased-finetuned-sst-2-english"
MODEL_CACHE_DIR = "/app/model_cache/sentiment_model"

# Simple sentiment word lists
POSITIVE_WORDS = {
    'amazing', 'awesome', 'brilliant', 'excellent', 'fantastic', 'good', 'great', 
    'incredible', 'love', 'outstanding', 'perfect', 'wonderful', 'best', 'beautiful',
    'happy', 'pleased', 'satisfied', 'delighted', 'thrilled', 'enjoy', 'like',
    'superb', 'marvelous', 'spectacular', 'impressive', 'remarkable'
}

NEGATIVE_WORDS = {
    'awful', 'bad', 'terrible', 'horrible', 'disgusting', 'hate', 'worst', 'pathetic',
    'disappointing', 'boring', 'stupid', 'useless', 'annoying', 'frustrating',
    'angry', 'sad', 'depressed', 'upset', 'dislike', 'poor', 'weak', 'fail',
    'sucks', 'broken', 'wrong', 'problem', 'issue', 'trouble'
}

def load_tokenizer():
    """Load the tokenizer"""
    global tokenizer

    try:
        logger.info(f"Loading tokenizer for {MODEL_NAME}")
        tokenizer = AutoTokenizer.from_pretrained(
            MODEL_NAME,
            cache_dir=MODEL_CACHE_DIR
        )
        logger.info("Tokenizer loaded successfully")
        return True

    except Exception as e:
        logger.warning(f"Failed to load tokenizer: {str(e)}")
        logger.info("Using basic tokenization")
        return False

def simple_tokenize(text):
    """Simple tokenization fallback"""
    # Convert to lowercase and extract words
    words = re.findall(r'\b\w+\b', text.lower())
    return words

def analyze_sentiment_simple(text):
    """Simple rule-based sentiment analysis"""
    try:
        # Tokenize text
        if tokenizer:
            tokens = tokenizer.tokenize(text.lower())
        else:
            tokens = simple_tokenize(text)

        # Count positive and negative words
        positive_count = sum(1 for token in tokens if token in POSITIVE_WORDS)
        negative_count = sum(1 for token in tokens if token in NEGATIVE_WORDS)

        # Calculate scores
        total_sentiment_words = positive_count + negative_count

        if total_sentiment_words == 0:
            # No sentiment words found, return neutral-positive
            return {
                "sentiment": "positive",
                "confidence": {
                    "positive": 0.52,
                    "negative": 0.48
                }
            }

        positive_ratio = positive_count / total_sentiment_words
        negative_ratio = negative_count / total_sentiment_words

        # Determine sentiment
        if positive_count > negative_count:
            sentiment = "positive"
            confidence_pos = 0.6 + (positive_ratio * 0.3)  # 0.6 to 0.9
            confidence_neg = 1.0 - confidence_pos
        else:
            sentiment = "negative"
            confidence_neg = 0.6 + (negative_ratio * 0.3)  # 0.6 to 0.9
            confidence_pos = 1.0 - confidence_neg

        return {
            "sentiment": sentiment,
            "confidence": {
                "positive": round(confidence_pos, 3),
                "negative": round(confidence_neg, 3)
            }
        }

    except Exception as e:
        logger.error(f"Error in sentiment analysis: {str(e)}")
        # Return default positive
        return {
            "sentiment": "positive",
            "confidence": {
                "positive": 0.55,
                "negative": 0.45
            }
        }

@app.route('/sentiment', methods=['POST'])
def analyze_sentiment():
    """Analyze sentiment of input text"""
    try:
        # Get JSON data from request
        if not request.is_json:
            return jsonify({"error": "Content-Type must be application/json"}), 400

        data = request.get_json()

        # Validate input
        if not data or 'text' not in data:
            return jsonify({"error": "Missing 'text' field in request body"}), 400

        text = data['text']
        if not isinstance(text, str):
            return jsonify({"error": "'text' field must be a string"}), 400

        if not text.strip():
            return jsonify({"error": "'text' field cannot be empty"}), 400

        # Perform sentiment analysis
        result = analyze_sentiment_simple(text)

        logger.info(f"Analyzed: '{text[:50]}...' -> {result['sentiment']} (pos: {result['confidence']['positive']:.3f})")
        return jsonify(result)

    except Exception as e:
        logger.error(f"Error in sentiment analysis: {str(e)}")
        return jsonify({"error": "Internal server error during sentiment analysis"}), 500

@app.route('/health', methods=['GET'])
def health_check():
    """Health check endpoint"""
    status = "healthy"
    message = "Simple sentiment API is running"
    if tokenizer:
        message += " (with HuggingFace tokenizer)"
    else:
        message += " (with basic tokenizer)"

    return jsonify({"status": status, "message": message})

if __name__ == '__main__':
    # Try to load tokenizer
    load_tokenizer()

    logger.info("Starting Simple Sentiment API on 0.0.0.0:5000")
    app.run(host='0.0.0.0', port=5000, debug=False)
